gnY(){return"\u041a\u0430\u0436\u0434\u044b\u0439 \u043f\u0440\u043e\u0435\u043a\u0442 \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442\u0441\u044f \u0441 \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u0438\u044f \u0433\u0440\u0430\u043d\u0438\u0446: \u0447\u0442\u043e \u0432\u0445\u043e\u0434\u0438\u0442, \u0447\u0442\u043e \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u0437\u0430 \u0440\u0430\u043c\u043a\u0430\u043c\u0438 \u0438 \u043a\u0430\u043a \u043a\u0430\u0436\u0434\u043e\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u0435 \u0441\u0432\u044f\u0437\u0430\u043d\u043e \u0441 \u043a\u0440\u0438\u0442\u0435\u0440\u0438\u0435\u043c \u043f\u0440\u0438\u0451\u043c\u043a\u0438. \u0411\u0435\u0437 \u044d\u0442\u043e\u0433\u043e \u0441\u043f\u0440\u0438\u043d\u0442 \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f \u0432 \u0433\u043e\u043d\u043a\u0443 \u0437\u0430 \u0441\u0440\u043e\u043a\u043e\u043c. \u0420\u0430\u0431\u043e\u0442\u0430\u044e \u0441 PO \u0438 \u0434\u0438\u0437\u0430\u0439\u043d\u043e\u043c \u0441 \u0441\u0430\u043c\u043e\u0433\u043e \u0441\u0442\u0430\u0440\u0442\u0430, \u0447\u0442\u043e\u0431\u044b \u0431\u044d\u043a\u043b\u043e\u0433 \u043e\u0442\u0440\u0430\u0436\u0430\u043b \u0442\u043e, \u0447\u0442\u043e \u043f\u043e\u0439\u0434\u0451\u0442 \u0432 \u043f\u0440\u043e\u0434\u0430\u043a\u0448\u0435\u043d, \u2014 \u0430 \u043d\u0435 \u0442\u043e, \u0447\u0442\u043e \u043a\u0440\u0430\u0441\u0438\u0432\u043e \u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0441\u044f \u0432 \u043f\u0440\u043e\u0442\u043e\u0442\u0438\u043f\u0435."},
